sql:
SELECT analyst_name, target_price
FROM analyst_ratings
WHERE target_price > 100;

external_knowledge:
Threshold for the 50-day moving average: 100;
Tech stocks: belong to the 'Technology' sector;
50-day moving average: a technical indicator calculated over the past 50 trading days.

sql:
SELECT AVG(value) 
FROM technical_indicators 
WHERE stock_id = (SELECT stock_id FROM stocks WHERE stock_symbol = 'TSLA');

SELECT analyst_name, AVG(target_price) AS average_target_price
FROM analyst_ratings
GROUP BY analyst_name;
